// O(n log n) time, O(n) space
function mergeSort(arr) {
  if (arr.length <= 1) return [arr, 0];
  const mid = Math.floor(arr.length / 2);
  const [left, lCount] = mergeSort(arr.slice(0, mid));
  const [right, rCount] = mergeSort(arr.slice(mid));
  const [merged, mCount] = merge(left, right);
  return [merged, lCount + rCount + mCount];
}
function merge(left, right) {
  const res = []; let i = 0, j = 0, count = 0;
  while (i < left.length && j < right.length) {
    if (left[i] <= right[j]) res.push(left[i++]);
    else { res.push(right[j++]); count += left.length - i; }
  }
  return [[...res, ...left.slice(i), ...right.slice(j)], count];
}
